import React, { useState } from "react";

const quickEmojis = [
  String.fromCodePoint(0x1F600),
  String.fromCodePoint(0x1F602),
  String.fromCodePoint(0x1F60D),
  String.fromCodePoint(0x1F525),
  String.fromCodePoint(0x1F44D)
];

export default function MessageForm({ onSend }) {
  const [text, setText] = useState("");
  const [files, setFiles] = useState([]);
  const [sending, setSending] = useState(false);

  const addEmoji = (emoji) => setText((prev) => `${prev}${emoji}`);

  const submit = (event) => {
    event.preventDefault();
    if (!text.trim() && !files.length) return;

    setSending(true);
    Promise.resolve(onSend({ content: text, files }))
      .then(() => {
        setText("");
        setFiles([]);
      })
      .finally(() => setSending(false));
  };

  return (
    <form className="message-form" onSubmit={submit}>
      <div className="message-input-wrap">
        <input
          type="text"
          placeholder="Type a message here..."
          value={text}
          onChange={(event) => setText(event.target.value)}
          maxLength={1000}
        />
        <div className="composer-tools">
          <label className="file-picker-btn">
            Attach
            <input type="file" multiple onChange={(event) => setFiles(Array.from(event.target.files || []).slice(0, 5))} />
          </label>
          {quickEmojis.map((emoji) => (
            <button key={emoji} type="button" className="emoji-btn" onClick={() => addEmoji(emoji)}>{emoji}</button>
          ))}
          {files.length ? <small className="attach-hint">{files.map((file) => file.name).join(", ")}</small> : null}
        </div>
      </div>
      <button className="primary-btn send-btn" type="submit" disabled={sending}>{sending ? "..." : "->"}</button>
    </form>
  );
}
